    <div className='card'>
      <form onSubmit={onMessageSubmit}>
        <h1>Messenger</h1>
        <div className='name-field'>
          <TextField
            name='name'
            onChange={(e) => onTextChange(e)}
            value={state.name}
            label='Name'
          />
        </div>
        <div>
          <TextField
            name='message'
            id='outlined-multiline-static'
            onChange={(e) => onTextChange(e)}
            value={state.message}
            label='Message'
          />
          <button>Send Message</button>
        </div>
      </form>
      <div className='render-chat'>
        <h1>Chat Log</h1>
        {renderChat()}
      </div>
    </div>
  );
}

export default App;
